public class Main {
    public static void main(String[] args) throws InterruptedException {
        // Method 1: Runnable lambda
        Thread t1 = new Thread(() -> {
            for (int i = 1; i <= 3; i++) {
                System.out.println("Thread 1: step " + i);
                try { Thread.sleep(10); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            }
        });

        // Method 2: extend Thread
        Thread t2 = new Thread(() -> {
            for (int i = 1; i <= 3; i++) {
                System.out.println("Thread 2: step " + i);
                try { Thread.sleep(10); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            }
        });

        t1.start();
        t2.start();
        t1.join(); // wait for t1 to finish
        t2.join(); // wait for t2 to finish
        System.out.println("Both done.");
    }
}

import java.util.concurrent.atomic.AtomicInteger;

public class Main {
    static int unsafeCounter = 0;
    static AtomicInteger safeCounter = new AtomicInteger(0);

    public static void main(String[] args) throws InterruptedException {
        Thread[] threads = new Thread[10];

        for (int i = 0; i < 10; i++) {
            threads[i] = new Thread(() -> {
                for (int j = 0; j < 1000; j++) {
                    unsafeCounter++;       // RACE CONDITION!
                    safeCounter.incrementAndGet(); // thread-safe
                }
            });
            threads[i].start();
        }

        for (Thread t : threads) t.join();

        System.out.println("Expected: 10000");
        System.out.println("Unsafe:   " + unsafeCounter + " (probably wrong!)");
        System.out.println("Safe:     " + safeCounter.get());
    }
}

