import java.util.concurrent.*;
import java.util.*;

public class Main {
    static int computeFactorial(int n) {
        int result = 1;
        for (int i = 2; i <= n; i++) result *= i;
        return result;
    }

    public static void main(String[] args) throws Exception {
        ExecutorService pool = Executors.newFixedThreadPool(4);

        List<Future<Integer>> futures = new ArrayList<>();

        for (int i = 1; i <= 8; i++) {
            final int n = i;
            futures.add(pool.submit(() -> computeFactorial(n)));
        }

        for (int i = 0; i < futures.size(); i++) {
            System.out.println((i+1) + "! = " + futures.get(i).get());
        }

        pool.shutdown();
    }
}

import java.util.concurrent.*;

public class Main {
    static String fetchUser(int id) {
        // Simulate network call
        return "User" + id;
    }

    static String fetchProfile(String user) {
        return user + "_profile";
    }

    public static void main(String[] args) throws Exception {
        // Chain async operations:
        CompletableFuture<String> pipeline = CompletableFuture
            .supplyAsync(() -> fetchUser(42))
            .thenApply(user -> fetchProfile(user))
            .thenApply(profile -> profile.toUpperCase());

        System.out.println(pipeline.get());

        // Combine two futures:
        CompletableFuture<String> f1 = CompletableFuture.supplyAsync(() -> "Hello");
        CompletableFuture<String> f2 = CompletableFuture.supplyAsync(() -> "World");

        String combined = f1.thenCombine(f2, (a, b) -> a + ", " + b).get();
        System.out.println(combined);
    }
}
